<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>2048</title>
<style>
  :root {
    --bg: #16171d;
    --panel: #22242e;
    --cell: #2c2f3a;
    --text: #e6e8ef;
    --accent: #8a7fff;
  }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    background: var(--bg);
    color: var(--text);
    font-family: system-ui, -apple-system, Segoe UI, Roboto, sans-serif;
    gap: 20px;
    padding: 24px;
  }
  h1 { margin: 0; font-size: 42px; letter-spacing: 2px; }
  .topbar {
    display: flex;
    align-items: center;
    gap: 16px;
    width: 100%;
    max-width: 420px;
    justify-content: space-between;
  }
  .scorebox {
    background: var(--panel);
    padding: 10px 18px;
    border-radius: 10px;
    text-align: center;
    min-width: 110px;
  }
  .scorebox .label {
    font-size: 12px;
    text-transform: uppercase;
    letter-spacing: 1px;
    opacity: 0.6;
  }
  #score { font-size: 26px; font-weight: 700; }
  #reset {
    background: var(--accent);
    color: #fff;
    border: none;
    padding: 12px 20px;
    font-size: 15px;
    font-weight: 600;
    border-radius: 10px;
    cursor: pointer;
  }
  #reset:hover { filter: brightness(1.1); }
  #board {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    grid-template-rows: repeat(4, 1fr);
    gap: 12px;
    background: var(--panel);
    padding: 12px;
    border-radius: 14px;
    width: 100%;
    max-width: 420px;
    aspect-ratio: 1 / 1;
  }
  .cell {
    background: var(--cell);
    border-radius: 8px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: clamp(20px, 7vw, 40px);
    font-weight: 700;
    color: var(--text);
    user-select: none;
  }
  .cell[data-v="0"] { color: transparent; }
  .cell[data-v="2"]    { background: #3a3d4a; }
  .cell[data-v="4"]    { background: #45485a; }
  .cell[data-v="8"]    { background: #6d5bd0; color:#fff; }
  .cell[data-v="16"]   { background: #7b63e0; color:#fff; }
  .cell[data-v="32"]   { background: #8a6bf0; color:#fff; }
  .cell[data-v="64"]   { background: #9973ff; color:#fff; }
  .cell[data-v="128"]  { background: #d98f3a; color:#fff; font-size: clamp(18px,6vw,34px);}
  .cell[data-v="256"]  { background: #e09a2a; color:#fff; font-size: clamp(18px,6vw,34px);}
  .cell[data-v="512"]  { background: #e8a51a; color:#fff; font-size: clamp(18px,6vw,34px);}
  .cell[data-v="1024"] { background: #f0b010; color:#fff; font-size: clamp(15px,5vw,28px);}
  .cell[data-v="2048"] { background: #ffbf00; color:#fff; font-size: clamp(15px,5vw,28px);}
  .hint { opacity: 0.5; font-size: 13px; }
</style>
</head>
<body>
  <h1>2048</h1>
  <div class="topbar">
    <div class="scorebox">
      <div class="label">Score</div>
      <div id="score">0</div>
    </div>
    <button id="reset">New Game</button>
  </div>
  <div id="board"></div>
  <div class="hint">Use the arrow keys to move.</div>

<script>
(function () {
  const SIZE = 4;
  let grid = [];
  let score = 0;

  const boardEl = document.getElementById('board');
  const scoreEl = document.getElementById('score');
  const cells = [];

  // Build DOM cells once.
  for (let i = 0; i < SIZE * SIZE; i++) {
    const c = document.createElement('div');
    c.className = 'cell';
    c.dataset.v = '0';
    boardEl.appendChild(c);
    cells.push(c);
  }

  function emptyGrid() {
    return Array.from({ length: SIZE }, () => new Array(SIZE).fill(0));
  }

  function render() {
    for (let r = 0; r < SIZE; r++) {
      for (let c = 0; c < SIZE; c++) {
        const v = grid[r][c];
        const el = cells[r * SIZE + c];
        el.dataset.v = String(v);
        el.textContent = v === 0 ? '' : String(v);
      }
    }
    scoreEl.textContent = String(score);
  }

  function emptyCells() {
    const out = [];
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        if (grid[r][c] === 0) out.push([r, c]);
    return out;
  }

  function spawn() {
    const empties = emptyCells();
    if (empties.length === 0) return;
    const [r, c] = empties[Math.floor(Math.random() * empties.length)];
    grid[r][c] = Math.random() < 0.9 ? 2 : 4;
  }

  // Slide+merge a single row toward the left (index 0). Returns
  // {row, gained}. Reusable for all directions by transforming input.
  function slideRow(row) {
    const nums = row.filter(v => v !== 0);
    const result = [];
    let gained = 0;
    for (let i = 0; i < nums.length; i++) {
      if (i + 1 < nums.length && nums[i] === nums[i + 1]) {
        const merged = nums[i] * 2;
        result.push(merged);
        gained += merged;
        i++; // skip the consumed tile — at most one merge
      } else {
        result.push(nums[i]);
      }
    }
    while (result.length < SIZE) result.push(0);
    return { row: result, gained };
  }

  function equal(a, b) {
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        if (a[r][c] !== b[r][c]) return false;
    return true;
  }

  // Extract a "line" for a given direction so it can be slid leftward,
  // then write it back.
  function getLine(dir, i) {
    const line = [];
    for (let k = 0; k < SIZE; k++) {
      if (dir === 'left')  line.push(grid[i][k]);
      if (dir === 'right') line.push(grid[i][SIZE - 1 - k]);
      if (dir === 'up')    line.push(grid[k][i]);
      if (dir === 'down')  line.push(grid[SIZE - 1 - k][i]);
    }
    return line;
  }

  function setLine(dir, i, line) {
    for (let k = 0; k < SIZE; k++) {
      if (dir === 'left')  grid[i][k] = line[k];
      if (dir === 'right') grid[i][SIZE - 1 - k] = line[k];
      if (dir === 'up')    grid[k][i] = line[k];
      if (dir === 'down')  grid[SIZE - 1 - k][i] = line[k];
    }
  }

  function move(dir) {
    if (!['left', 'right', 'up', 'down'].includes(dir)) return false;
    const before = grid.map(row => row.slice());
    let gainedTotal = 0;
    for (let i = 0; i < SIZE; i++) {
      const { row, gained } = slideRow(getLine(dir, i));
      setLine(dir, i, row);
      gainedTotal += gained;
    }
    const changed = !equal(before, grid);
    if (changed) {
      score += gainedTotal;
      spawn();
      render();
    }
    return changed;
  }

  function reset() {
    grid = emptyGrid();
    score = 0;
    spawn();
    spawn();
    render();
  }

  function setBoard(arr) {
    grid = emptyGrid();
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        grid[r][c] = (arr[r] && arr[r][c]) ? arr[r][c] : 0;
    render();
  }

  document.addEventListener('keydown', (e) => {
    const map = {
      ArrowLeft: 'left', ArrowRight: 'right',
      ArrowUp: 'up', ArrowDown: 'down',
    };
    const dir = map[e.key];
    if (dir) {
      e.preventDefault();
      move(dir);
    }
  });

  document.getElementById('reset').addEventListener('click', reset);

  window.game = {
    size: SIZE,
    reset,
    move,
    board: () => grid.map(row => row.slice()),
    setBoard,
    score: () => score,
  };

  reset();
})();
</script>
</body>
</html>
